import React, { useState } from 'react';
import SearchBar from './components/SearchBar';
import ProfileCard from './components/ProfileCard';
import RepoList from './components/RepoList';
import StatsChart from './components/StatsChart';
import api from './utils/api';
import './App.css';

function App() {
  const [user, setUser] = useState(null);
  const [repos, setRepos] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchProfile = async (username) => {
    setLoading(true);
    setError('');
    try {
      const userData = await api.getUser(username);
      const userRepos = await api.getRepos(username);
      setUser(userData);
      setRepos(userRepos.slice(0, 10)); // Top 10 repos
    } catch (err) {
      setError('User not found or API error');
    }
    setLoading(false);
  };

  return (
    <div className="App min-vh-100 bg-dark text-light">
      <header className="bg-primary text-white py-4">
        <div className="container">
          <h1 className="mb-0"><i className="fab fa-github me-2"></i>GitHub Profile Analyzer</h1>
        </div>
      </header>
      <main className="container py-5">
        <SearchBar onSearch={fetchProfile} loading={loading} />
        {error && <div className="alert alert-danger mt-4">{error}</div>}
        {loading && <div className="text-center mt-4"><div className="spinner-border text-primary" role="status"></div></div>}
        {user && (
          <>
            <div className="row mt-5">
              <div className="col-lg-8">
                <RepoList repos={repos} />
              </div>
              <div className="col-lg-4">
                <StatsChart user={user} />
              </div>
            </div>
            <ProfileCard user={user} />
          </>
        )}
      </main>
    </div>
  );
}

export default App;
